detailed_optimizations.code_changes:
将第一个 GEMM 的循环顺序从 i-j-k 改为 i-k-j，使对 B 矩阵的访问变为行连续访问，从而允许编译器自动生成 SIMD 向量化指令并消除对 tmp 的非连续写入。同理，将第二个 GEMM 的循环顺序重组，并提取常数乘法。

```cpp
// 优化后的 CPU 实现
// 1. 第一个 GEMM: tmp = alpha * A * B
for (i = 0; i < _PB_NI; i++) {
    for (j = 0; j < _PB_NJ; j++) {
        tmp[i][j] = SCALAR_VAL(0.0);
    }
    for (k = 0; k < _PB_NK; k++) {
        DATA_TYPE alpha_A = alpha * A[i][k];
        #pragma omp simd
        for (j = 0; j < _PB_NJ; j++) {
            tmp[i][j] += alpha_A * B[k][j];
        }
    }
}
// 2. 第二个 GEMM: D = tmp * C + beta * D
for (i = 0; i < _PB_NI; i++) {
    #pragma omp simd
    for (j = 0; j < _PB_NL; j++) {
        D[i][j] *= beta;
    }
    for (k = 0; k < _PB_NJ; k++) {
        DATA_TYPE tmp_val = tmp[i][k];
        #pragma omp simd
        for (j = 0; j < _PB_NL; j++) {
            D[i][j] += tmp_val * C[k][j];
        }
    }
}
```
